        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: 'Kalispel Territory — Priest Lake Country', text: 'The Priest River watershed was Kalispel (Pend d\"Oreilles) territory. The Kalispel people fished the river for cutthroat trout and bull trout, and hunted the surrounding Selkirk Mountains. Jesuit missionaries, who arrived in the 1840s, gave the river and lake their current names.', src: 'Kalispel Tribe of Indians; Bonner County Historical Society' }] },
          { era: 'modern', entries: [{ yr: '2019', title: 'Selkirk Caribou — Last of Their Kind', text: 'The Selkirk Mountains above the Priest River watershed were home to the last remaining woodland caribou herd in the contiguous United States. Despite decades of conservation effort, the herd dwindled to near zero by 2019, making the Priest River corridor one of the last places these animals were seen in the Lower 48.', src: 'USFWS; Idaho Fish and Game' }] },
        ],
        docs: [],
