        docs: [{ t: 'North Umpqua Wild & Scenic River Management Plan', s: 'USFS Umpqua NF', y: 2000, tp: 'Federal', pg: 130 , url: 'https://www.rivers.gov/sites/rivers/files/documents/plans/north-umpqua-plan.pdf'}],
