        g: '11274000', avg: 1200, histFlow: 1050, mx: 195, my: 108, abbr: 'CA',
        desc: "Flows from the Sierra Nevada through Yosemite National Park and the spectacular Merced River Canyon — one of the most scenic river corridors in California. The iconic Class IV–V Merced Gorge between Briceburg and Bagby delivers technical Sierra granite whitewater. The Yosemite Valley section flows past El Capitan and Half Dome. National Wild & Scenic River since 1987.",
        desig: 'National Wild & Scenic River (1987) · Yosemite National Park (upper reach)',
        secs: ['Yosemite Valley — Class I–II, past El Capitan and Half Dome', 'El Portal to Briceburg — Class III–IV, transition canyon', 'Briceburg to Bagby — Class IV–V, Merced Gorge, expert only'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: "Ahwahneechee (Southern Sierra Miwok) — Valley of the Ahwahneechee", text: "The Merced River flows through the heart of Ahwahneechee (Southern Sierra Miwok) territory. 'Yosemite Valley' was 'Ahwahnee' — 'place of the gaping mouth' — to the Ahwahneechee. The river was central to their subsistence and cultural life for thousands of years. The 1851 Mariposa Battalion forced them from the valley.", src: 'Yosemite Valley Native American History Program; NPS; Tuolumne Band of Me-Wuk Indians' }] },
          { era: 'survey', entries: [{ yr: '1987', title: 'Merced Wild & Scenic — Protecting the Gorge', text: "Congress designated the Merced Wild & Scenic in 1987, specifically protecting the Merced Gorge section from dam proposals that had been floated since the 1940s. The designation established the Merced's status as one of California's most protected river corridors.", src: 'USFS Sierra NF; Wild & Scenic Rivers Act (1987)' }] },
          { era: 'modern', entries: [{ yr: '2014', title: 'Yosemite Valley Plan — Restoring the Merced Floodplain', text: "NPS's Yosemite Valley Plan began restoring the Merced's natural floodplain in Yosemite Valley, removing developed facilities from the flood zone and allowing the river to meander more naturally — the first major floodplain restoration in a national park of this scale.", src: 'NPS Yosemite; Yosemite Merced Wild & Scenic River Management Plan (2014)' }] },
        ],
        docs: [{ t: 'Merced Wild & Scenic River Comprehensive Management Plan', s: 'NPS Yosemite', y: 2014, tp: 'Federal', pg: 280 , url: 'https://www.rivers.gov/sites/rivers/files/documents/plans/merced-plan.pdf'}],
        revs: [{ u: 'merced_gorge_regular', d: 'May 2024', s: 5, t: 'Briceburg to Bagby at 2,400 cfs — Ned Bull, Gray\'s Grindstone, and Nightmare Island all hitting perfectly. Best expert Sierra Nevada canyon run outside the Tuolumne.' }, { u: 'yosemite_river_paddler', d: 'Jun 2024', s: 4, t: 'El Portal section at 1,800 cfs — Class III through Yosemite with the valley walls above. Half Dome visible at one bend. Surreal.' }],
        outs: [{ n: 'Zephyr Whitewater Expeditions', d: 'Merced River gorge raft and kayak trips', l: 'zrafting.com' }, { n: 'ARTA River Trips', d: 'Merced River guided trips', l: 'arta.org' }],
