        outs: [{ n: 'Nantahala Outdoor Center', d: 'NOC — eastern whitewater institution since 1972', l: 'noc.com' }, { n: 'Rolling Thunder River Company', d: 'Nantahala gorge raft trips', l: 'rollingthunderrafting.com' }],
