        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: "Cherokee — High Country River", text: "'Watauga' derives from a Cherokee word meaning 'land beyond' or 'beautiful water.' The river headwaters were in the highest Cherokee territory — the Blue Ridge above Boone, NC was among the last Cherokee hunting grounds in North Carolina.", src: 'Eastern Band of Cherokee Indians; Watauga County Historical Society' }] },
          { era: 'logging', entries: [{ yr: '1772', title: 'Watauga Settlement — First Free and Independent Government in America', text: "The Watauga Association (1772) was the first independent government formed by American colonists west of the Appalachians — and is sometimes called the first written constitution in American history. It was established by settlers in the Watauga River valley before American independence.", src: 'Tennessee Historical Commission; Carter County Historical Society' }] },
          { era: 'modern', entries: [{ yr: '2023', title: 'Watauga Gorge — High Country Kayaking Destination', text: 'The Watauga Gorge section has developed a devoted following among High Country kayakers and Appalachian State University paddling community. TVA dam release coordination has improved predictability of runnable flows.', src: 'American Whitewater; Appalachian Outdoors Club' }] },
        ],
